async function main() {
  if (posts.length < 30) {
    console.warn(`Only ${posts.length} posts in script. Add more to reach 30.`);
  }
  console.log(`📅 Seeding ${posts.length} scheduled blog posts...\n`);

  // Start date: tomorrow at 9 AM UTC, one per day
  const now = new Date();
  const startDate = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1, 9, 0, 0));

  for (let i = 0; i < posts.length; i++) {
    const p = posts[i];
    const publishAt = new Date(startDate.getTime() + i * 24 * 60 * 60 * 1000);

    // Upsert: if slug exists, update; else insert
    await db.execute(sql`
      INSERT INTO blog_posts (title, slug, excerpt, content, published, scheduled_publish_at)
      VALUES (${p.title}, ${p.slug}, ${p.excerpt}, ${p.content}, false, ${publishAt})
      ON CONFLICT (slug) DO UPDATE SET
        title = EXCLUDED.title,
        excerpt = EXCLUDED.excerpt,
        content = EXCLUDED.content,
        scheduled_publish_at = EXCLUDED.scheduled_publish_at
    `);

    console.log(`  ✓ ${publishAt.toISOString().slice(0,10)}  ${p.slug}`);
  }

  console.log(`\n✅ ${posts.length} posts scheduled (one per day at 9 AM UTC).`);
  console.log(`   First publish: ${startDate.toISOString().slice(0,10)}`);
  console.log(`   Last publish: ${new Date(startDate.getTime() + (posts.length-1) * 86400000).toISOString().slice(0,10)}`);
}

main().catch(err => { console.error("❌", err); process.exit(1); });
